<template>
    <div class="tiler">
            <transition-group name="collapse">
                <component
                class="tile"
                v-for="tile in tileFilter"
                v-bind:key="tile.link"
                v-bind:is="getCompentName(tile.link)"
                :FpActive="FpActive" />
            </transition-group>
    </div>
</template>

<script>
import headerTile from './headerTile.vue'
import bioTile from './bioTile.vue'
import filmTile from './filmTile.vue'

export default {
    name: 'tileLoader',
    components: {
        headerTile,
        bioTile,
        filmTile
    },
    props: {
        Tiles: {},
        tileActive: {},

    },
    methods: {
        getCompentName(type) {
            switch (type) {
                case 'header':
                    return 'headerTile'
                case 'bio':
                    return 'bioTile'
                case 'film':
                    return 'filmTile'
                default:
                    return 'empty'
            }
        },
    },
    computed: {
        FpActive () {
            return this.$store.state.FpActive
        },
        tileFilter () {
            return this.Tiles.filter(tile => tile == this.tileActive)
        }
    }
}
</script>

<style scoped>

.tiler {
    width: 100vw;
    height: 100vh;
    overflow: hidden;
}
.tile {
    width: 100vw;
    position: relative;
    margin: 0;
    overflow-x: hidden;
    z-index: 1;
}

.collapse-enter-active, .collapse-leave-active {
	transition: all .5s;
}
.collapse-enter, .collapse-leave-to {
	height: 0;
    opacity: 0;
    transform: scale(0.7);
}
</style>