<template>
    <div class="tile">
        <input type="range" class="thumbSize" min="1" max="5" v-model="thumbSize">
        <div class="sidescroll" >
            <div class="filmlist">
                <transition-group name="collapse">
                <filmThumb
                v-for="film in filmFilter"
                v-bind:key="film.link"
                :filmo="film"
                :filmActive="filmActive"
                :thumbSize="thumbSize" />
                </transition-group>
            </div>
        </div>
    </div>
</template>

<script>
import filmThumb from './filmThumb.vue'
import filmJSON from './JSON/films.json'

export default {
    name: 'filmTile',
    props: {
        FpActive: {},
    },
    data: function() {
        return {
            Films: filmJSON.reverse(),
            filmActive: {},
            thumbSize: '4',
        }
    },
    components: {
        filmThumb
    },
    methods: {
        filmSelect(selected){
            this.filmActive = selected;
        },
    },
    computed: {
        filmFilter () {
            return this.Films.filter(film => film.names[this.FpActive.alt])
        },
        listStyle () {
            return (Math.ceil(this.filmFilter.length / 4) + 8) * 44 + 'vh'
        }
    }

}
</script>

<style scoped>
.tile {
    height: 100vh;
    overflow-y: hidden;
}
.thumbSize {
    position: absolute;
    z-index: 2;
}
.sidescroll {
    height: 100vw;
    width: 100vh;
    margin: 0;
    transform-origin: left top;
    transform: rotate(-90deg) translateX(-100vh);
    top: 0;
    overflow-x: hidden;
}
.filmlist {
    position: absolute;
    left: -5vh;
    height: 90vh;
    display: flex;
    flex-direction: column;
    flex-wrap: wrap;
    transform-origin: left top;
    transform: rotate(90deg) translateY(-100vh);
}
@media only screen and (max-width: 100vh) {
    .tile {
        overflow-y: auto;
    }
    .thumbSize {
        display: none;
    }
    .sidescroll {
        width: 100vw;
        height: auto;
        transform-origin: none;
        transform: none;
    }
    .filmlist {
        position: absolute;
        left: 0;
        height: auto;
        width: 100vw;
        transform-origin: none;
        transform: none;
        flex-wrap: nowrap;
    }
}
.collapse-enter-active {
    animation: slideIn 0.5s;
}
.collapse-leave-active {
	animation: slideOut 0.5s;
}

@keyframes slideIn {
  from {

    opacity: 0
  }
  to {
 
    opacity: 1;
  }
}
@keyframes slideOut {
  from {

    opacity: 1;
  }
  to {

    opacity: 0;
  }
}
</style>