import { createApp } from 'vue'
import { createStore } from 'vuex'
import App from './App.vue'

import FpJSON from './components/JSON/fellpellers.json'
import TilesJSON from './components/JSON/tiles.json'

const store = createStore({
    state: {
        isMobile: '',
        Fellpellers: FpJSON,
        Tiles: TilesJSON,
        FpActive: {},
        tileActive: {},
        navToggle: false,
    },
    mutations: {
        Fp (state, selected) {
            state.FpActive = selected
        },
        tile (state, selected) {
            state.tileActive = selected
        },
        toggler (state, boolean) {
            state.navToggle = boolean
        },
        isMobile (state) {
            if(/Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent)) {
                state.isMobile = true
            } else {
                state.isMobile = false
            }
        }
    }
  })

const app = createApp(App)
app.use(store)
app.mount('#app')
