<template>
    <div class="nav">
        <navButton
        v-for="fellpeller in Fellpellers" 
        v-bind:key="fellpeller.alt"
        :list="Fellpellers"
        :FpStyle="fellpeller" 
        :FpActive="FpActive"
        :toggle="toggle"
        :Nav="['Fp', '100', 'vh']"
        :text="'na'"
        :depth="'2'"
        v-on:click="[togglePage(fellpeller),
        navOpen()]" />
    </div>
</template>

<script>
import navButton from './navButton.vue'

export default {
    name: 'navFp',
    data: function() {
        return {
        }
    },
    components: {
        navButton
    },
    methods: {
        togglePage(selection) {
            this.$store.commit('Fp', selection)
        },
        navOpen() {
            this.$store.commit('toggler', true)
        }
    },
    computed: {
        Fellpellers () {
            return this.$store.state.Fellpellers
        },
        FpActive () {
            return this.$store.state.FpActive
        },
        toggle () {
            return this.$store.state.navToggle
        }
    },
    created() {
        this.togglePage(this.Fellpellers[0])
    }
    
}
</script>

<style scoped>

.nav {
    position: fixed;
    top: 0;
    left: 0;
    height: auto;
    flex-direction: column;
    justify-content: space-around;
    z-index: 4
}

</style>