<template>
        <div class="player" v-bind:style="thumbStyle">
            <div class="thumbnail" >
            <img v-bind:src="'https://i.ytimg.com/vi/' + filmo.link + '/maxresdefault.jpg'" />
            <div class="filmTitle">
                {{ filmo.alt }}
            </div></div>
            
        </div>
      
</template>

<script>
export default {
    name: 'filmThumb',
    props: {
        filmo: {},
        filmActive: {},
        FpActive: {},
        thumbSize: String,
    },
    data: function() {
        return {
            thumbStyle: {
                height: '',
                width: '',
                marginTop: '',
            }
        }
    },
    methods: {
        thumbStyling() {
            var height = 90 / (6 - this.thumbSize);
            this.thumbStyle.height = height + 'vh';
            this.thumbStyle.width = (height / 9) * 16 + 'vh';
        }
    },
    created() {
        this.thumbStyling()
    },
    updated() {
        this.thumbStyling()
    }

}
</script>

<style scoped>
.player {
    display: flex;
    flex-wrap: wrap;
    flex-direction: column;
}
.thumbnail {
    display: flex;
    transition: all 0.5s;
}
.filmTitle {
    position: absolute;
    top: 50%;
    width: 100%;
    color: black;
    z-index: 2;
    opacity: 0;
    transition: opacity .5s;
}

img {
    height: 100%;
    width: 100%;
    transition: all 0.5s;
}
.thumbnail:hover {
    cursor: pointer;
    transform: scale(0.9);
}
.thumbnail:hover .filmTitle {
    opacity: 1;
}
.thumbnail:hover img {
    opacity: 0.7;
}

@media only screen and (max-width: 100vh) {
 .thumbnail {
     width: 100vw;
 }
}

.test {
    position: absolute;
    top: 0;
    width: 100vw;
    background-color: rgba(0, 0, 0, 0.8);
    height: 90vh;
    z-index: 3;
}
.exit {
    cursor: pointer;
    height: 10vh;
}
</style>