<template>
    <div class="tile">
        <transition-group name="slide">
            <div
            class="bio"
            v-for="bio in bioFilter"
            v-bind:key="bio.name">
                <img class="bioimage" v-bind:src="require('../assets/bio/' + bio.image)" />
                <div class="biotext">
                    <span v-bind:style="[bioStyle]">{{ bio.name }}</span>
                    {{ bio.bio }}
                </div>
            </div>
        </transition-group>
    </div>
</template>

<script>
import bioJSON from './JSON/bios.json'

export default {
    name: 'bioTile',
    props: {
        FpActive: {}
    },
    data: function() {
        return {
            Bios: bioJSON,
            bioStyle: {
                background: '',
            }
        }
    },
    methods: {
        bioStyling() {
            this.bioStyle.background = 'linear-gradient(to top, ' + this.FpActive.bgcolor + ' 50%, transparent 50%)'
        }
    },
    computed: {
        bioFilter () {
            return this.Bios.filter(bio => bio.name == this.FpActive.alt)
        }
    },
    created() {
        this.bioStyling()
    },
    updated() {
        this.bioStyling()
    }
}
</script>

<style scoped>
.tile {
    position: relative;
    height: 100vh;
    width: auto;
    overflow-y: scroll;
}
.bio {
    display: flex;
    flex-direction: row;
    justify-content: space-evenly;
    position: absolute;
    left: 0vw;
    width: 100vw;
    height: 100vh;
    overflow-y: scroll;
    z-index: -2;
}
.bioimage {
    height: 80vh;
    margin: auto;
    z-index: -1;
}
.biotext {
    height: 80vh;
    min-width: 80vh;
    width: 50vw;
    margin: auto;
    overflow-y: scroll;
    font-family: Arial, Geneva, Helvetica, sans-serif;;
    font-size: 3vw;
    z-index: 1;
}
span {
    font-family: "BodoniXT";
}

@media only screen and (max-width: 160vh) {
    .bio {
        flex-direction: column;
        justify-content: space-evenly;
        height: auto;
    }
    .bioimage {
        width: 80vw;
        height: auto;
        margin-bottom: 5vw;
        margin-top: 10vw;
        z-index: -3;
    }
    .biotext {
        width: 80vw;
        min-width: 0;
        height: fit-content;
        margin-bottom: 5vw;
        font-size: 6vw;
    }
}

.slide-enter-active {
    animation: slideIn 0.5s;
}
.slide-leave-active {
	animation: slideOut 0.5s;
}

@keyframes slideIn {
  from {
    left: 100vw;
  }
  to {
    left: 0;
  }
}
@keyframes slideOut {
  from {
    left: 0;
  }
  to {
    left: -100vw;
  }
}
</style>