<template>
    <div class="header">
        <transition-group name="slideup">
        <div
        class="headerfloat"
        v-for="Fp in Fellpellers"
        v-bind:key="Fp.alt">
            <h1>{{ Fp.first }}</h1>
            <h2>{{ Fp.last }}</h2>
        </div>
        </transition-group>
    </div>
</template>

<script>
export default {
    name: 'headerTile',
    props: {
        FpActive: {}
    },
    computed: {
        Fellpellers () {
            return this.$store.state.Fellpellers.filter(Fp => Fp.alt == this.FpActive.alt)
        }
    }

}
</script>

<style scoped>
.header {
    position: absolute;
    height: 100vh;
    width: 100vw;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: flex-end;
    overflow: hidden;
}
.headerfloat {
    position: absolute;
    width: auto;
    float: right;
}
h1 {
    font-size: 10vw;
    line-height: 7.5vw;
    margin: 0;
}
h2 {
    font-size: 2.5vw;
    margin: 0;
}
@media only screen and (max-width: 100vh) {
}

.slideup-enter-active {
    animation: slideIn 0.5s;
}
.slideup-leave-active {
	animation: slideOut 0.5s;
}

@keyframes slideIn {
  from {
    transform: translateY(100%);
    opacity: 0;
  }
  to {
    transform: translateY(0%);
    opacity: 1;
  }
}
@keyframes slideOut {
  from {
    transform: translateY(0%);
    opacity: 1;
  }
  to {
    transform: translateY(-100%);
    opacity: 0;
  }
}
</style>