<template>
  <div id="app">
    <navDesktop />
    <tileLoader :Tiles="Tiles" :tileActive="tileActive" />
  </div>
</template>

<script>
import navDesktop from './components/navDesktop.vue'
import tileLoader from './components/tileLoader.vue'

export default {
  name: 'App',
  components: {
    navDesktop,
    tileLoader
  },
  methods: {
    mobileCheck() {
      this.$store.commit('isMobile')
    }
  },
  computed: {
    Tiles () {
        return this.$store.state.Tiles
    },
    tileActive () {
        return this.$store.state.tileActive
    },
    isMobile () {
      return this.$store.state.isMobile
    }
  },
  created() {
    this.mobileCheck()
  }
}
</script>

