<template>
    <div class="container" v-if="toggle">
        <navButton 
        v-for="tile in Tiles"
        v-bind:key="tile.link"
        :list="Tiles"
        :FpActive="FpActive"
        :tileActive="tileActive"
        :toggle="toggle"
        :Nav="['Tile', '50', 'vh']"
        :text="tile"
        :depth="'2'"
        v-on:click="[toggleTile(tile)]" />
    </div>
</template>

<script>
import navButton from './navButton.vue'

export default {
    name: 'navTiles',
    data: function() {
        return {
        }
    },
    components: {
        navButton
    },
    methods: {
        toggleTile(selection) {
            this.$store.commit('tile', selection)
        }
    },
    computed: {
        Tiles () {
            return this.$store.state.Tiles
        },
        FpActive () {
            return this.$store.state.FpActive
        },
        tileActive () {
            return this.$store.state.tileActive
        },
        toggle () {
            return this.$store.state.navToggle
        }
    },
    created() {
        this.toggleTile(this.Tiles[0])
    }
}
</script>

<style scoped>
.container {
    flex-direction: column;
    position: fixed;
    top: 50%;
    left: 50%;
    height: 60vh;
    width: auto;
    padding-right: 100vw;
    padding-left: 100vw;
    overflow-y: scroll;
    transform: translate(-50%, -50%);
    z-index: 1;
}
</style>