<template>
    <div
    class="button"
    v-on:mouseover="[hover = depth / 2, buttonStyling()]"
    v-on:mouseleave="[hover = depth, buttonStyling()]"
    v-on:mousedown="[hover = 0, buttonStyling()]"
    v-on:mouseup="[hover = depth / 2, buttonStyling()]"
    v-bind:style="[buttonStyle]">
    <div class="text" v-if="text" v-bind:style="[buttonText]">{{text.name}}</div>
    </div>
</template>

<script>

export default {
    name: 'navButton',
    props: {
        list: {},
        FpStyle: {},
        FpActive: {},
        tileActive: {},
        toggle: Boolean,
        Nav: Array,
        text: {},
        depth: String,
    },
    data: function() {
        return {
            buttonStyle: {
                height: '',
                width: '',
                borderRadius: '',
                bottom: '',
                right: '',
                marginTop: '',
                marginLeft: '',
                backgroundColor: '',
                color: '',
                boxShadow: '',
                visibility: '',
                transition: '',
                zIndex: '',
            },
            buttonText: {
                fontSize: '',
                lineHeight: '',
                padding: '',
            },
            hover: this.depth
        }
    },
    methods: {
        buttonStyling() {
            var height = '';
            if(this.Nav[0] === "Fp") {
                height = this.Nav[1] / this.list.length * 0.7;
                this.buttonStyle.height = height + this.Nav[2];
                this.buttonStyle.width = this.buttonStyle.height;
                this.buttonStyle.borderRadius = '50%';
                this.buttonStyle.marginLeft = this.Nav[1] / this.list.length * 0.2 + this.Nav[2];
                this.buttonStyle.marginTop = !this.toggle ? this.FpStyle != this.list[0] ? '-' + this.buttonStyle.height : this.Nav[1] / this.list.length * 0.15 + this.Nav[2] : this.FpStyle != this.list[0] ? this.Nav[1] / this.list.length * 0.3 + this.Nav[2] : this.Nav[1] / this.list.length * 0.15 + this.Nav[2];
                this.buttonStyle.backgroundColor = this.FpStyle.bgcolor;
                this.buttonStyle.color = this.FpStyle.color;
                this.buttonStyle.visibility = !this.toggle ? this.FpStyle == this.FpActive ? 'visible' : 'hidden' : 'visible';
                this.buttonStyle.transition = this.toggle ? 'margin-top 0.5s cubic-bezier(0,1,.86,1)' : 'margin-top 0.5s cubic-bezier(0,1,.86,1), visibility 0s linear 0.5s';
                this.buttonStyle.zIndex = this.FpStyle == this.list[0] ? '5' : this.FpStyle == this.FpActive ? '5' : '4';
            } if(this.Nav[0] === "Tile") {
                height = this.Nav[1] / 5;
                this.buttonStyle.height = height + this.Nav[2];
                this.buttonStyle.width = 'auto';
                this.buttonStyle.borderRadius = height / 2 + this.Nav[2];
                this.buttonStyle.marginTop = height / 2 + this.Nav[2];
                this.buttonStyle.backgroundColor = this.FpActive.bgcolor;
                this.buttonStyle.color = this.FpActive.color;
                this.buttonText.fontSize = height / 2 + this.Nav[2];
                this.buttonText.lineHeight = height / 2 + this.Nav[2];
                this.buttonText.padding = height / 4 + this.Nav[2];
            }
            
            if (this.text == this.tileActive) {
                this.buttonStyle.bottom = 0;
                this.buttonStyle.right = 0;
                this.buttonStyle.boxShadow = this.buttonStyle.bottom + ' ' + this.buttonStyle.bottom + ' 0';
            } else {
                this.buttonStyle.bottom = this.hover + this.Nav[2];
                this.buttonStyle.right = this.buttonStyle.bottom;
                this.buttonStyle.boxShadow = this.buttonStyle.bottom + ' ' + this.buttonStyle.bottom + ' 0';
            }
            
        },
    },
    created() {
        this.buttonStyling()
    },
    updated() {
        this.buttonStyling()
    }
}
</script>

<style scoped>

.button {
    cursor: pointer;
    position: relative;
}

</style>